const b=BOLT[d];
const gr=GRADE[grK];
const clB=CL_MAT[partMatKey];
const dep=+gv('dep');

const Db=(b.dw+b.dh)/2;
const K=b.p/(2*Math.PI*d)+0.577*mt*b.d2/d+mw*Db/(2*d);
const Knd=K*d;
const At=b.p/(2*Math.PI)+0.577*mt*b.d2;
const dAs=Math.sqrt(4*b.As/Math.PI);

const Fy_denom=1+3*Math.pow(3/dAs*At,2);
const Fy=gr.Sy*b.As/Math.sqrt(Fy_denom)/1000;
const T_lim=Knd*Fy;

const nTh=Math.max(1,(dep*d-0.5*b.p)/b.p);
const bArea=(Math.PI/4)*(b.dw*b.dw-b.dh*b.dh);
const bA=CL_MAT[partMatKey].bearing;
const Fbrk=gr.Su*b.As/1000;
const Fstr=clB.tau*Math.PI*d*0.5*b.p*nTh*0.577/1000;
const FbA=bA*bArea/1000;

const failModes=[
  {name:'座面陥没 A',F:FbA},
  {name:'山せん断',F:Fstr},
  {name:'ボルト破断',F:Fbrk}
].sort((a,b)=>a.F-b.F);

const dominant=failModes[0].name;
const T_fail=failModes[0].F*Knd;
const T_jis=T_lim/sf;           // JIS標準値（ボルト強度基準）
const softMaterials=new Set(['aluminum','cast_iron','brass','resin']);
const isSoft=softMaterials.has(partMatKey);
const T_rec=isSoft?Math.min(T_jis,T_fail/sf):T_jis;
const isMaterialLimit=isSoft&&T_fail/sf<T_jis;

ge('res-torque').textContent=T_rec.toFixed(2);
